-	args := append(editorArgs, tmpPath)
-	cmd := exec.Command(editorCmd, args...)
-	cmd.Stdin = os.Stdin
-	cmd.Stdout = os.Stdout
-	cmd.Stderr = os.Stderr
-
-	if err := cmd.Run(); err != nil {
