+	out := make([]Conflict, 0)
+	for path, agentsMap := range byPath {
+		if len(agentsMap) < 2 {
+			continue
+		}
+		conflict := Conflict{Path: path}
+		var last time.Time
+		for agent, ts := range agentsMap {
+			conflict.Agents = append(conflict.Agents, agent)
+			if ts.After(last) {
+				last = ts
+			}
+		}
+		conflict.LastAt = last
+		conflict.Severity = "warning"
+		out = append(out, conflict)
+	}
+	return out
